const EXPECTED_TOKEN = $json.gatewayToken || 'change-me';
const BASE_URL = ($json.instanceUrl || 'http://localhost:5678').replace(/\/+$/, '') + '/api/v1';
const n8nApiKey = $json.n8nApiKey || '';

const headers = $json.headers || {};
const body = $json.body || {};
const action = (body.action || '').trim();
const params = body.params || {};
const apiKey = headers['x-api-key'] || headers['X-API-Key'] || headers['X-api-key'] || '';

if (apiKey !== EXPECTED_TOKEN) {
  return [{ json: { action_type: 'error', status: 401, success: false, error: 'Unauthorized', message: 'Invalid or missing X-API-Key header' } }];
}

const B = BASE_URL;
function cleanQs(obj) {
  return Object.fromEntries(Object.entries(obj).filter(([_, v]) => v !== undefined && v !== null && v !== ''));
}

const actionDefs = {
  list_workflows: () => ({ method: 'GET', url: B + '/workflows', qs: cleanQs({ active: params.active, limit: params.limit || 100, cursor: params.cursor, tags: params.tags }) }),
  get_workflow: () => ({ method: 'GET', url: B + '/workflows/' + params.workflowId }),
  create_workflow: () => ({ method: 'POST', url: B + '/workflows', body: params.workflow || {} }),
  update_workflow: () => ({ method: 'PUT', url: B + '/workflows/' + params.workflowId, body: params.workflow || {} }),
  delete_workflow: () => ({ method: 'DELETE', url: B + '/workflows/' + params.workflowId }),
  activate_workflow: () => ({ method: 'POST', url: B + '/workflows/' + params.workflowId + '/activate' }),
  deactivate_workflow: () => ({ method: 'POST', url: B + '/workflows/' + params.workflowId + '/deactivate' }),
  trigger_workflow: () => ({ method: 'POST', url: B + '/workflows/' + params.workflowId + '/run', body: params.data ? { data: params.data } : {} }),
  list_executions: () => ({ method: 'GET', url: B + '/executions', qs: cleanQs({ workflowId: params.workflowId, status: params.status, limit: params.limit || 20, cursor: params.cursor, includeData: params.includeData }) }),
  get_execution: () => ({ method: 'GET', url: B + '/executions/' + params.executionId }),
  delete_execution: () => ({ method: 'DELETE', url: B + '/executions/' + params.executionId }),
  stop_execution: () => ({ method: 'POST', url: B + '/executions/' + params.executionId + '/stop' }),
  list_credentials: () => ({ method: 'GET', url: B + '/credentials', qs: cleanQs({ limit: params.limit || 100, cursor: params.cursor }) }),
  create_credential: () => ({ method: 'POST', url: B + '/credentials', body: params }),
  delete_credential: () => ({ method: 'DELETE', url: B + '/credentials/' + params.credentialId }),
  list_variables: () => ({ method: 'GET', url: B + '/variables', qs: cleanQs({ limit: params.limit || 100, cursor: params.cursor }) }),
  create_variable: () => ({ method: 'POST', url: B + '/variables', body: { key: params.key, value: params.value } }),
  delete_variable: () => ({ method: 'DELETE', url: B + '/variables/' + params.variableId }),
  list_tags: () => ({ method: 'GET', url: B + '/tags', qs: cleanQs({ limit: params.limit || 100, cursor: params.cursor }) }),
  create_tag: () => ({ method: 'POST', url: B + '/tags', body: { name: params.name } }),
  update_tag: () => ({ method: 'PUT', url: B + '/tags/' + params.tagId, body: { name: params.name } }),
  delete_tag: () => ({ method: 'DELETE', url: B + '/tags/' + params.tagId }),
  list_users: () => ({ method: 'GET', url: B + '/users', qs: cleanQs({ limit: params.limit || 100, cursor: params.cursor }) }),
  generate_audit: () => ({ method: 'POST', url: B + '/audit', body: params.additionalData ? { additionalData: params.additionalData } : {} }),
  list_projects: () => ({ method: 'GET', url: B + '/projects', qs: cleanQs({ limit: params.limit || 100, cursor: params.cursor }) }),
  pull_source_control: () => ({ method: 'POST', url: B + '/source-control/pull', body: { force: params.force || false } }),
  push_source_control: () => ({ method: 'POST', url: B + '/source-control/push', body: { message: params.message || 'Update from mobile app', force: params.force || false } }),
};

const allActions = Object.keys(actionDefs).concat(['get_system_info', 'list_endpoints']);

if (action === 'get_system_info') {
  return [{ json: { action_type: 'system_info' } }];
}

if (action === 'list_endpoints') {
  return [{ json: { action_type: 'success', success: true, action: 'list_endpoints', data: { total: allActions.length, endpoints: allActions, categories: { workflows: ['list_workflows','get_workflow','create_workflow','update_workflow','delete_workflow','activate_workflow','deactivate_workflow','trigger_workflow'], executions: ['list_executions','get_execution','delete_execution','stop_execution'], credentials: ['list_credentials','create_credential','delete_credential'], variables: ['list_variables','create_variable','delete_variable'], tags: ['list_tags','create_tag','update_tag','delete_tag'], users: ['list_users'], audit: ['generate_audit'], projects: ['list_projects'], source_control: ['pull_source_control','push_source_control'], meta: ['get_system_info','list_endpoints'] } } } }];
}

const defFn = actionDefs[action];
if (!defFn) {
  return [{ json: { action_type: 'error', success: false, status: 400, error: 'Unknown action', message: 'Action "' + action + '" not supported. Call list_endpoints for all available actions.', available_actions: allActions } }];
}

const cfg = defFn();
const bodyData = cfg.body || {};
const qsData = cfg.qs || {};
const hasBody = Object.keys(bodyData).length > 0;
const hasQs = Object.keys(qsData).length > 0;

return [{ json: { action_type: 'api_call', action, method: cfg.method, url: cfg.url, bodyData, qsData, hasBody, hasQs, n8nApiKey } }];

const apiData = $input.first().json;
const req = $('Map Action').first().json;
const hasError = apiData.message && (apiData.code >= 400 || apiData.httpCode >= 400);

// n8n API list responses: { data: [...], nextCursor }
// unwrap to avoid double nesting
let responseData;
if (Array.isArray(apiData.data)) {
  responseData = {
    items: apiData.data,
    total: apiData.data.length,
    nextCursor: apiData.nextCursor || null
  };
} else {
  responseData = apiData;
}

return [{ json: { success: !hasError, action: req.action, data: responseData } }];
